import random

def backoff_delay(attempt: int, base: float = 0.5, cap: float = 60.0) -> float:
    # Full-jitter exponential backoff: spreads retries to avoid herds
    exp = min(cap, base * (2 ** attempt))
    return random.uniform(0, exp)

# attempt 0 -> up to 0.5s, attempt 3 -> up to 4s, attempt 7+ -> up to 60s

