import hashlib
from dataclasses import dataclass, field
from typing import Callable


class TransientError(Exception):
    pass


class PermanentError(Exception):
    pass


@dataclass
class Message:
    body: bytes
    message_id: str | None = None
    attempts: int = 0


@dataclass
class DedupStore:
    """Stands in for a dedup table with a unique constraint."""
    seen: set[str] = field(default_factory=set)

    def claim(self, key: str) -> bool:
        # Atomic claim: returns True only the first time (like INSERT .. ON CONFLICT)
        if key in self.seen:
            return False
        self.seen.add(key)
        return True

    def release(self, key: str) -> None:
        # Roll back the claim if the side effect failed (same transaction)
        self.seen.discard(key)


@dataclass
class DeadLetterQueue:
    messages: list[tuple[Message, str]] = field(default_factory=list)

    def put(self, msg: Message, reason: str) -> None:
        self.messages.append((msg, reason))


def dedup_key(msg: Message) -> str:
    return msg.message_id or hashlib.sha256(msg.body).hexdigest()


class IdempotentConsumer:
    def __init__(self, dedup: DedupStore, dlq: DeadLetterQueue,
                 handler: Callable[[Message], None], max_attempts: int = 5):
        self.dedup = dedup
        self.dlq = dlq
        self.handler = handler
        self.max_attempts = max_attempts

    def consume(self, msg: Message) -> str:
        """Returns 'acked', 'deduped', or 'dead-lettered'. Never loops forever."""
        msg.attempts += 1
        key = dedup_key(msg)

        # Step 1: atomic dedup claim + side effect in one transaction
        if not self.dedup.claim(key):
            return "deduped"  # already processed: ack without re-applying

        try:
            self.handler(msg)          # the side effect
        except TransientError as e:
            self.dedup.release(key)    # undo claim so a retry can succeed
            if msg.attempts >= self.max_attempts:
                self.dlq.put(msg, f"max attempts exceeded: {e}")
                return "dead-lettered"
            return self.consume(msg)   # retry (in practice: requeue with backoff)
        except PermanentError as e:
            self.dedup.release(key)
            self.dlq.put(msg, f"permanent failure: {e}")
            return "dead-lettered"

        # Step 2: claim + effect committed together -> safe to ack
        return "acked"


# --- demonstration ---
if __name__ == "__main__":
    applied: list[str] = []

    def handler(msg: Message) -> None:
        if b"poison" in msg.body:
            raise PermanentError("unparseable")
        applied.append(msg.message_id or "?")

    dedup, dlq = DedupStore(), DeadLetterQueue()
    c = IdempotentConsumer(dedup, dlq, handler)

    m = Message(body=b"ok", message_id="m1")
    assert c.consume(m) == "acked"
    assert c.consume(Message(body=b"ok", message_id="m1")) == "deduped"  # duplicate
    assert c.consume(Message(body=b"poison", message_id="m2")) == "dead-lettered"
    assert applied == ["m1"]           # effect applied exactly once
    assert len(dlq.messages) == 1       # poison message captured, no loop

from dataclasses import dataclass
from fnmatch import fnmatchcase

# Routing key convention:  tenant.region.entity.action
# Examples:
#   acme.eu.order.created
#   acme.us.invoice.issued
# Topic wildcards: '*' = exactly one segment, '#' = zero or more segments.


def routing_key(tenant: str, region: str, entity: str, action: str) -> str:
    for part in (tenant, region, entity, action):
        if not part or "." in part or "*" in part or "#" in part:
            raise ValueError(f"invalid segment: {part!r}")
    return f"{tenant}.{region}.{entity}.{action}"


def topic_matches(binding: str, key: str) -> bool:
    """Implements AMQP topic matching: '*' one word, '#' zero or more words."""
    b, k = binding.split("."), key.split(".")

    def rec(bi: int, ki: int) -> bool:
        if bi == len(b):
            return ki == len(k)
        if b[bi] == "#":
            # '#' consumes any number of remaining words
            return any(rec(bi + 1, kj) for kj in range(ki, len(k) + 1))
        if ki == len(k):
            return False
        if b[bi] == "*" or b[bi] == k[ki]:
            return rec(bi + 1, ki + 1)
        return False

    return rec(0, 0)


@dataclass(frozen=True)
class Binding:
    queue: str
    pattern: str


def binding_plan(tenant: str, region: str) -> list[Binding]:
    """Bindings needed to onboard a tenant + region. Producer is untouched."""
    return [
        Binding(f"audit.{tenant}", f"{tenant}.#"),                 # all events for tenant
        Binding("billing.global", "*.*.invoice.*"),               # all invoices, any tenant
        Binding(f"fulfilment.{region}", f"*.{region}.order.created"),  # regional orders
    ]


def route(key: str, bindings: list[Binding]) -> set[str]:
    return {b.queue for b in bindings if topic_matches(b.pattern, key)}


if __name__ == "__main__":
    bindings = binding_plan("acme", "eu")

    k_order = routing_key("acme", "eu", "order", "created")
    assert route(k_order, bindings) == {"audit.acme", "fulfilment.eu"}

    k_invoice = routing_key("acme", "us", "invoice", "issued")
    # us order is not in the eu fulfilment binding; invoice hits audit + billing
    assert route(k_invoice, bindings) == {"audit.acme", "billing.global"}

    k_other_tenant = routing_key("globex", "eu", "order", "created")
    # different tenant: audit.acme must NOT match; fulfilment.eu still does
    assert route(k_other_tenant, bindings) == {"fulfilment.eu"}

    print("routing scheme verified")
